    });
    const res3 = await createLearningViaHttp(baseUrl, user, workspaceId, {
      text: "Learning Gamma.", learning_type: "precedent", priority: "low", target_agents: ["pm_agent"],
    });
    const id1 = ((await res1.json()) as { learningId: string }).learningId;
